const body = $input.first().json.body || $input.first().json;
const metin = body.metin || '';
const ders_adi = body.ders_adi || 'Ders Notu';
const tip = body.tip || 'metin';
const url = body.url || '';
let video_id = '';
if (tip === 'youtube' && url) {
  const match = url.match(/(?:v=|youtu\.be\/)([\w-]{11})/);
  if (match) video_id = match[1];
}
return [{ json: { metin, ders_adi, tip, url, video_id } }];

const raw = $input.first().json;
let content = '';
if (typeof raw === 'string') content = raw;
else if (raw.data && typeof raw.data === 'string') content = raw.data;
else if (raw.body && typeof raw.body === 'string') content = raw.body;
else content = JSON.stringify(raw);
const ders_adi = $('Girişi Hazırla').first().json.ders_adi;
const temiz = content.substring(0, 6000).replace(/[\x00-\x08\x0B\x0C\x0E-\x1F]/g, ' ');
return [{ json: { metin: temiz, ders_adi } }];

const ders_adi = $json.ders_adi;
const temiz = ($json.metin || '').substring(0, 6000).replace(/[\x00-\x08\x0B\x0C\x0E-\x1F]/g, ' ');
return [{ json: { metin: temiz, ders_adi } }];

const response = $input.first().json;
const content = response.choices[0].message.content;
let parsed;
try {
  const cleaned = content.replace(/```json/g, '').replace(/```/g, '').trim();
  parsed = JSON.parse(cleaned);
} catch(e) {
  parsed = { ozet: content.substring(0, 500), anahtar_kavramlar: 'Parse hatası', madde_madde: content.substring(0, 500), sorular: 'Parse hatası' };
}
const ders_adi = $('Girişi Hazırla').first().json.ders_adi;
const str = (v) => {
  if (Array.isArray(v)) return v.map(x => typeof x === 'object' ? JSON.stringify(x) : String(x)).join(', ');
  if (typeof v === 'object' && v !== null) return JSON.stringify(v);
  return String(v || '');
};
return [{ json: { ders_adi: str(ders_adi), ozet: str(parsed.ozet), anahtar_kavramlar: str(parsed.anahtar_kavramlar), madde_madde: str(parsed.madde_madde), sorular: str(parsed.sorular) } }];
